import type { Interpretation } from "./types";

export const ASPECTS: Record<string, Interpretation> = {
  "sun-moon-trine": { title: "Sun trine Moon", body: "Your will and your needs drink from the same well. What you set out to do and what actually nourishes you tend to point the same direction, so you move through life without the constant inner negotiation most people mistake for normal. In lived terms: you recover from hard days faster, you trust your own read on a room, and **the public you and the private you are recognizably the same person** — a coherence that steadies everyone near you.\n\nThe growth edge is that ease can go unexamined. Harmony this native rarely announces when it needs updating, so check in sometimes: is the self you keep agreeing with still the one you are becoming? **Treat your inner peace as a resource to spend**, not a museum piece — lend your calm to the people and projects that need it most." },
  "sun-moon-sextile": { title: "Sun sextile Moon", body: "There is an open door between who you are and what you feel, and it swings easily whenever you use it. This is the signature of the person who pauses — actually pauses — before a decision and asks the body how it lands. When you do, choices carry unusual grace; when you skip it, life still works, just flatter and more effortful. **Cooperation between head and heart is on offer here**, not installed by default.\n\nThe practice is consultation. Before the yes, before the move, before the reply you would regret — one breath, one honest check of the inner weather. Do this often enough and it becomes reflex, and the reflex becomes a life that fits. **Your feelings are data, not interruptions.** Build them into the process on purpose." },
  "sun-mercury-trine": { title: "Sun trine Mercury", body: "When you speak, you sound like yourself — which is rarer than it sounds. Your thoughts arrive already shaped by who you are, so self-expression costs you little composure: no drafting three versions of the message, no rehearsing your own opinions in the mirror. In lived life this looks like **saying the true thing without losing the room**, narrating your experience clearly, and being trusted to mean exactly what you say.\n\nThe edge: fluency can crowd. When words come easily, silence starts to feel like failure and other people's slower sentences like invitations to interrupt. Practice **letting other minds finish** — the ones that stammer toward their truth often carry the piece yours skipped. Your gift was never speed. It is coherence, and coherence keeps." },
  "sun-mercury-sextile": { title: "Sun sextile Mercury", body: "There is a friendly bridge between who you are and how you explain yourself, and every crossing strengthens it. Saying your goals out loud actually sharpens them; writing your life down clarifies it. You think best in dialogue — with a page, a trusted friend, a voice memo recorded at midnight. **Articulation is how you find out what you already know.**\n\nSo take the invitation seriously, as practice rather than personality. Keep the journal, send the long message, tell someone what you are building before you are sure of it. **Your direction gets clearer every time you give it words.** Nothing about this is automatic — which means everything about it is yours, earned one honest sentence at a time." },
  "sun-venus-trine": { title: "Sun trine Venus", body: "Warmth is not something you perform; it is woven into how you arrive. People soften around you before you have said much, doors open with less friction, and beauty — in objects, in gestures, in other people — finds you easily. In lived life this is **the gift of being welcome**: rooms tend to make space for you, and your affection for the world reads plainly on your face.\n\nThe edge is an old one: being liked can quietly start substituting for being known. Grace this natural can become a costume you forget you are wearing. The practice is **letting people see the unpolished draft** — the opinion that might not land, the want that is not charming. You were loved before you learned to be pleasant. Keep proving it to yourself." },
  "sun-venus-sextile": { title: "Sun sextile Venus", body: "Grace is available to you the moment you reach for it. Your identity leans naturally toward connection, beauty, and diplomacy — an open lane rather than an automatic one. When you deliberately bring warmth to what you do — the thoughtful note, the room arranged with care, the conflict softened without being buried — **the results carry a polish people remember** long after the details fade.\n\nThe practice is intentional sweetness: build beauty into your ordinary output on purpose, not just on occasions. Dress the work, honor the small ritual, thank people specifically instead of generally. None of it is frivolous. **Aesthetics is a form of respect**, and this aspect makes you fluent in it whenever you choose to speak it. Choose it more often than feels necessary." },
  "sun-mars-trine": { title: "Sun trine Mars", body: "Deciding and doing arrive almost simultaneously in you. Will and action run as one clean motion — you do not psych yourself up, you simply begin, and your follow-through has the unhurried confidence of someone who has never doubted their own engine. In lived life: **you are formidable when you care**, and the people around you learn quickly that your yes means motion.\n\nThe refinement this asks for is aim. Fire this smooth can burn through commitments that were never worth the fuel, simply because starting feels so good. Practice **choosing your battles as deliberately as you win them** — and let some invitations to act go unanswered entirely. Strength that can decline is stronger than strength that cannot." },
  "sun-mars-sextile": { title: "Sun sextile Mars", body: "Courage is on offer here — not installed, offered. Your vitality responds beautifully to challenges chosen on purpose: the project started before you felt ready, the direct question asked out loud, the physical practice that reminds you **your body is on your side**. Left unclaimed, this aspect idles politely in the background. Claimed, it compounds year over year.\n\nSo claim it in small denominations. One brave ask per week. One thing begun instead of researched further. The confidence you keep waiting to feel is downstream of action, not upstream of it — **you become bold by spending boldness**, and this aspect quietly refills the account of anyone who keeps spending." },
  "sun-jupiter-trine": { title: "Sun trine Jupiter", body: "You carry an optimism that is not naive — it is well-fed. You assume there is room for you, room to grow, room to try again, and that assumption keeps proving itself because you act on it. In lived life: opportunities recognize you, teachers appear at the right chapters, and **your faith in the bigger frame is contagious** in the best possible way.\n\nThe edge is coasting. Fortune this friendly can lull you into letting the current do all the swimming, and gifts unmatched by effort eventually thin out. **Finish what grace starts** — match your luck with follow-through, and be generous on purpose rather than only by mood. Abundance that circulates is the only kind that keeps growing." },
  "sun-jupiter-sextile": { title: "Sun sextile Jupiter", body: "Doors open for you when you knock — that is the precise contract of this aspect. Expansion, mentors, well-timed breaks: all of it responsive to your initiative, none of it delivered unasked. In lived life it looks like the application sent on a whim that changes everything, **the yes said slightly before you felt ready** that turns out to be the hinge of a decade.\n\nSo make knocking a habit. Apply for the thing one size too big. Introduce yourself to the person whose work you admire. Growth here is not a lottery; it is **a correspondence you have to keep answering**. The people who seem lucky with this aspect are simply the ones who never stopped writing back." },
  "sun-saturn-trine": { title: "Sun trine Saturn", body: "Discipline does not fight your nature; it is your nature, quietly. You build in layers, respect real limits, keep your word, and finish what others abandon — a steadiness that reads as trustworthiness long before anyone can name why. In lived life: **you are the person things can be built on**, including, most importantly, your own future.\n\nThe permission this grants is bigger than the caution. Structure like yours can hold far more weight than you assume, so let yourself want big things — the decade-long project, the body of work, the life designed rather than defaulted into. **Ambition is safe in your hands.** Aim your patience at something genuinely worthy of it, and start earlier than modesty suggests." },
  "sun-saturn-sextile": { title: "Sun sextile Saturn", body: "Maturity is offered to you in workable doses. Responsibility arrives at a pace you can actually metabolize: the mentor who takes you seriously, the role slightly heavier than the last one, the deep satisfaction of a thing done properly and signed with your name. **Time is willing to be your ally here** — provided you commit to the long arc instead of the quick exit.\n\nThe practice is choosing depth over churn. Pick commitments worth years, then keep them visible: the craft, the savings, the promise renewed on ordinary days when no one is watching. Every season you complete adds quiet authority. **You do not have to be old to be solid** — you just have to keep showing up on schedule." },
  "sun-uranus-trine": { title: "Sun trine Uranus", body: "Your originality does not have to shout. You simply do not fit the mold, and — rarer still — you are at peace with that. Reinvention comes to you without the rupture others endure: you shed outgrown selves like seasons, not surgeries. For anyone living outside the standard scripts, this is gold: **difference sits in you as inheritance, not injury**, something handed down rather than something gone wrong.\n\nThe invitation is application. Freedom that never lands anywhere stays a party trick; freedom aimed at something — a body of work, a community, a way of living that others can borrow courage from — becomes lineage. **Put your strangeness to work.** The mold you never fit was always the wrong container for what you are carrying." },
  "sun-uranus-sextile": { title: "Sun sextile Uranus", body: "Every so often, a genuinely new version of you becomes available — quietly, without crisis, if you take it. This aspect deals in timely exits from stale identities: the haircut that is really a threshold, the name for yourself that finally fits, the role left one season before it soured. **Reinvention is on offer in humane doses**, small enough to survive, real enough to matter.\n\nThe practice is staying curious about your own edges. Ask, every so often: what am I still performing that I no longer mean? Then let one thing go. **The refresh works, but you have to press it** — and every press teaches you, a little more deeply, that changing is something you survive beautifully." },
  "sun-neptune-trine": { title: "Sun trine Neptune", body: "Imagination runs through your identity like watercolor through wet paper. You sense atmospheres, absorb the unspoken, and create from a place most people cannot name — your sense of self has soft borders, which makes you permeable to beauty and to other people's inner weather alike. **You were built for the invisible work**: art, compassion, meaning-making, the tending no one sees.\n\nA gift this porous needs a container or it evaporates into lovely intentions. The practice is craft: the discipline that gives your visions edges, the schedule that gives your compassion limits it can survive. **Anchor the mist in something you can finish.** Boundaries will not dim your shimmer — they are what lets other people finally see it." },
  "sun-neptune-sextile": { title: "Sun sextile Neptune", body: "Inspiration keeps leaving the door ajar for you — music that reorders a hard day, dreams that arrive with homework attached, sudden tenderness for strangers on the train. Your identity is enriched by everything subtle, but only when you make room for it. **Ten minutes of stillness collects what this aspect delivers**; a life with no margin loses the delivery entirely.\n\nSo build the margin. A morning page, a walk without a podcast, a small ritual no one else needs to understand. What you are cultivating is a working relationship with your own depths — **the soft signal is real, and it responds to attention.** Feed it regularly and it will feed you back for the rest of your life." },
  "sun-pluto-trine": { title: "Sun trine Pluto", body: "Depth is your default setting. You metabolize change that would flatten other people and come back with your core not just intact but clarified — losses turn to compost, endings to instructions. Power sits easily in your hands, often before you notice you are holding it. **People sense there is bedrock in you**, and they are right to build on it.\n\nThe question to keep asking is not whether you are strong — it is what the strength is for. Power unexamined defaults to control; power examined becomes stewardship. **Choose regeneration over domination**, in yourself first. The truest use of a nature like yours is helping other people survive their own transformations, because you have the map." },
  "sun-pluto-sextile": { title: "Sun sextile Pluto", body: "Transformation is offered to you in installments rather than earthquakes. When you willingly look at what drives you — the pattern beneath the preference, the old wound beneath the ambition — you find reserves of will that renew your entire sense of purpose. **Self-honesty pays out in power here**, gently, repeatedly, for as long as you keep the account open.\n\nThe practice: one honest excavation per season. The therapy question you have been avoiding, the journal entry that names the real reason, the conversation with yourself you keep rescheduling. Nothing dramatic — just regular contact with your own depths. **What you face on purpose never has to ambush you**, and every pattern you compost becomes ground you can build on." },
  "moon-mercury-trine": { title: "Moon trine Mercury", body: "Your feelings arrive pre-translated. Where others grope for words, you can name the ache, the delight, the exact shade of your hesitation — and naming a feeling is half of tending it. In lived life this makes you **the friend who can say the unsayable gently**, the one who gives shape to what the whole room was sensing but could not phrase.\n\nThe edge: fluency is not depth. Some feelings deserve to be sat with rather than summarized — grief especially resists tidy sentences, and love outgrows them. Practice **letting a feeling stay wordless a while longer** before you file it under something manageable. The report can wait. The experience is the point, and it only happens once." },
  "moon-mercury-sextile": { title: "Moon sextile Mercury", body: "There is an open channel between your heart and your language, waiting to be used. Journaling converts murk into insight; the honest conversation drains the swamp a formal apology never could; the voice memo to yourself at midnight is real medicine. **Your feelings become workable the moment you give them words** — but the giving is entirely up to you.\n\nSo say the thing. The people who love you cannot act on what you assume is obvious, and half of loneliness is often just unsent sentences. The practice: **narrate your inner weather out loud** to someone safe, regularly, before it becomes a storm system. It is not oversharing. It is maintenance, and it is how you stay findable." },
  "moon-venus-trine": { title: "Moon trine Venus", body: "Comfort flows from you the way warmth comes off a stone that held the sun all day. People feel tended in your presence — fed, softened, safe enough to exhale — and you often do not notice you are doing it. **Your tenderness is real currency**, the kind that makes a house a home and turns a handful of people into chosen family.\n\nThe edge is distribution. Care this abundant tends to flow toward whoever needs it loudest rather than whoever returns it. Practice **spending your sweetness where it is reciprocated** — and keep a standing account for yourself: the good meal, the soft blanket, the beauty that is only for you. You count as someone you tend. Act like it." },
  "moon-venus-sextile": { title: "Moon sextile Venus", body: "Sweetness is available on request in your inner life. Small rituals of beauty genuinely regulate you — the good cup, the flowers bought for no reason, the playlist matched to the weather — and your nervous system responds to loveliness the way plants respond to light. **Comfort, for you, is a practice with instructions**, not a mood you wait for.\n\nThe instructions are simple: notice what soothes you, then build it into ordinary days rather than saving it for emergencies. **Beauty is maintenance, not reward.** You do not have to earn softness by suffering first. Schedule it like anything else that keeps you alive — because for you, quietly and literally, it does." },
  "moon-mars-trine": { title: "Moon trine Mars", body: "Your emotions do not stall you; they fuel you. Anger converts to advocacy, restlessness to a long walk, longing to a plan — feeling moves through you into action with almost no drag. In lived life this means **you protect what you love quickly and well**, and your care shows up with its sleeves already rolled.\n\nThe edge is pace. Motion this clean can outrun tenderness — yours and other people's — and not every feeling wants to be solved. Practice **staying soft one beat longer** than instinct suggests: sit with the friend before fixing, feel the grief before filing it under fuel. Sometimes presence is the action, and stillness is the strongest move available." },
  "moon-mars-sextile": { title: "Moon sextile Mars", body: "When something matters to you, the will to act on it is right there — offered, not imposed. This aspect deals in honest confrontation, decisive care, and the protective move made while it still counts. **The gap between feeling and doing is yours to close**, and it closes best while the feeling is still warm in your hands.\n\nThe practice: act on your care within the day. Send the check-in text now, name the resentment before it ferments, book the thing your body has been asking for all month. **Courage on behalf of your own feelings** is a skill, and every rep makes the next one easier. Your emotions want a body that follows through. Give them one." },
  "moon-jupiter-trine": { title: "Moon trine Jupiter", body: "Your inner weather trends toward generous skies. You recover, you forgive, you find the bigger frame almost by reflex, and your emotional abundance spills onto whoever is nearby — the extra plate at the table, the benefit of the doubt given twice. **Hope is your resting state**, and it has earned its keep through actual storms.\n\nThe one caution: buoyancy can float straight past pain that wanted acknowledging — especially your own. Practice landing. Let the sad thing be sad for a full afternoon before you find its silver lining. **Grief metabolized whole becomes wisdom**; grief skipped becomes weight you carry anyway. Your optimism is strong enough to hold the truth. Let it." },
  "moon-jupiter-sextile": { title: "Moon sextile Jupiter", body: "Emotional growth comes to you as friendly invitations: the new city, the wiser friend, the book that reframes your childhood, the tradition borrowed respectfully and made your own. Say yes and **your heart expands its floor plan** — another room for another kind of love, another window with a longer view of what a life can hold.\n\nThis aspect never insists, which means the breadth of your inner life is genuinely up to you. The practice is deliberate yes-saying: travel that stretches, company that differs from you, meaning sought on purpose rather than stumbled into. **Choose the bigger table** whenever it is offered. You were never meant to feel at home in only one room." },
  "moon-saturn-trine": { title: "Moon trine Saturn", body: "Your feelings have good bones. You self-soothe without spectacle, keep confidences like a vault, and offer the kind of steadiness people quietly build their lives around. In a crisis you are the one who gets everyone fed and home safe. **Reliability is your love language**, whether or not anyone ever taught you to call it that.\n\nThe edge: composure can calcify into a wall. Being dependable and being known are meant to coexist — practice letting someone see you mid-struggle, not just after you have handled it alone. **You are allowed to be held, not just to hold.** The people who love you would consider it an honor, not a burden. Test that. It holds." },
  "moon-saturn-sextile": { title: "Moon sextile Saturn", body: "Emotional maturity is offered to you as a craft, not a birthright — which is better, honestly, because crafts can be practiced and birthrights only inherited. Boundaries, routines, the dignity of a need stated plainly: each one steadies your inner life when you commit to it. **Your calm is built, brick by chosen brick**, and no one can repossess what you built yourself.\n\nSo build on schedule. The bedtime kept, the boundary restated without apology, the weekly ritual that tells your nervous system what to expect. **Structure is a form of self-tenderness** here — not a cage but a greenhouse. What you construct around your feelings determines how tall they can safely grow." },
  "moon-uranus-trine": { title: "Moon trine Uranus", body: "Your emotional life refuses to fossilize. You need change the way others need certainty, and you handle upheaval with a strange, bright competence — the move, the ending, the reinvention that terrifies your friends barely raises your pulse. **Freedom is a nutrient for you**, not a luxury, and you visibly wilt without it.\n\nThe practice is letting a few attachments stay boring and permanent anyway. Roots do not cancel wings; they are what makes the long flights survivable. Choose one or two people, places, or rituals to keep through every self you become. **Continuity, chosen freely, is its own liberation** — the kind no one can revoke and no reinvention has to cost you." },
  "moon-uranus-sextile": { title: "Moon sextile Uranus", body: "Fresh emotional air is always one honest experiment away for you. Change the routine, tell the unexpected truth, befriend someone unlike anyone you already know — each small shake-up returns you to yourself renewed rather than rattled. **Liberation is offered in doses here**, gentle ones, long before life would ever have to prescribe the large kind.\n\nTake the doses on schedule. Rearrange the room when the feelings stagnate; say the true thing at the dinner table; let yourself want something entirely off-script. The practice is **treating novelty as emotional hygiene** — small, regular, deliberate. People who refresh on purpose rarely reach the point of needing to burn it all down." },
  "moon-neptune-trine": { title: "Moon trine Neptune", body: "You feel the room before you enter it. Empathy this fluent borders on clairvoyance — moods, dreams, and other people's unspoken sorrows pass through you like weather through an open house. In lived life you are the one strangers confide in on trains, **the person who hears what was not said** and answers it anyway, gently, as if it had been.\n\nThe essential skill is sorting: which feelings are actually yours? Porousness without inventory becomes exhaustion wearing compassion's coat. Practice the boundary that is not a wall — the pause that asks, is this mine to carry? **Compassion with limits is still compassion**; it is simply the kind you can sustain for fifty years instead of five.\n" },
  "moon-neptune-sextile": { title: "Moon sextile Neptune", body: "Your inner life keeps offering the mystic's side door: vivid dreams, sudden tenderness, art that undoes you a little on an ordinary Tuesday. None of it forces itself on you — the subtle world is polite here, **knocking softly and entering only when invited**, which means a rushed life can miss it entirely.\n\nSo invite it, deliberately. A creative practice, a candle lit with intention, ten quiet minutes before the phone comes on. What you gain is a depth ordinary logic cannot supply: the hunch that protects you, the image that heals something words could not reach. **Make room and the room fills.** Your sensitivity was never a flaw awaiting management — it is a door awaiting use." },
  "moon-pluto-trine": { title: "Moon trine Pluto", body: "You feel in full fathoms, and it does not frighten you. Intimacy, grief, devotion — you go where the depth is and come back with something true, and people trust you with their underworld because **you have clearly mapped your own.** Nothing about the human dark is theoretical to you, which is exactly why you are safe company inside it.\n\nKeep some of that fierceness for your own tending. The ones who hold everyone's deep water often forget that they, too, need a shore. Practice receiving — the check-in you did not initiate, the care you did not ration out first. **Your depths deserve a witness too**, and letting someone in is not a demotion. It is the advanced course." },
  "moon-pluto-sextile": { title: "Moon sextile Pluto", body: "Emotional excavation is offered to you gently here — the chance to trace a pattern all the way to its root without the roof caving in. Therapy, the honest late-night talk, the journal that finally tells the truth: these are your instruments, and **they work at whatever pace you set**, which is the mercy of this aspect.\n\nThe practice is regular small digs rather than rare cave-ins. Follow one reaction back to its origin this month; name one inherited fear and check whether it is still yours to keep. **Every old feeling you compost becomes ground you grow from** — and unlike the crisis version of transformation, this one lets you keep your footing the whole way down." },
  "mercury-venus-trine": { title: "Mercury trine Venus", body: "Your words wear well. Tact, wit, and warmth braid through how you communicate, so even your disagreements tend to leave the furniture intact — you can decline an invitation, deliver hard feedback, or end an argument with everyone's dignity still standing. **Language is a place you host people**, and they consistently leave better than they arrived.\n\nThe one hazard: beautiful phrasing can sand the edges off a truth that needed them. Diplomacy in service of clarity is a gift; diplomacy in service of avoidance is just a delay with good manners. Practice **letting the true thing stay pointed** when it matters. Your charm will survive the occasional sharp sentence — and your closest relationships will deepen because of it." },
  "mercury-venus-sextile": { title: "Mercury sextile Venus", body: "Charm and clarity are willing to collaborate whenever you ask them to. The compliment that is actually specific, the graceful message that unknots a conflict, the toast that lands and gets quoted later — these are learnable arts for you, **half-finished at birth and waiting for practice** to complete them.\n\nSo finish them. Study the writers whose warmth you admire; revise the important message once more before sending; say the kind thing out loud instead of merely thinking it near someone. **A pleasant voice used with intention opens rooms** — and keeps them open long after cleverness alone would have worn thin. What you are building is not performance. It is hospitality, in language." },
  "mercury-mars-trine": { title: "Mercury trine Mars", body: "Your mind has excellent reflexes. Thought becomes speech becomes action in one fluid motion, and you argue the way athletes move — economically, without wasted effort or performative heat. In lived life: **you say the direct thing while others are still drafting**, meetings end sooner when you are in them, and problems get named before they get expensive.\n\nThe maturing edge: quickness can win exchanges and lose people. Speed reads as dismissal to slower, deeper thinkers — who often carry exactly the piece your velocity skipped. Practice **letting the pause do some of the talking.** Your mind does not dull when it waits; it gains the one thing speed cannot buy, which is range." },
  "mercury-mars-sextile": { title: "Mercury sextile Mars", body: "Decisiveness is on the table every time you open your mouth. This aspect offers the clean ask, the direct question, the plan spoken aloud so it becomes real and other people can hold you to it — **verbal courage as a standing invitation** rather than a default setting you can take for granted.\n\nAccept it in small denominations. Ask for the actual number. Name the tension in the room instead of managing around it. Say what you want before you have secured permission to want it. Each direct sentence trains the next one, and **things move when you speak plainly** — careers, relationships, the stuck conversation everyone else was politely orbiting." },
  "mercury-jupiter-trine": { title: "Mercury trine Jupiter", body: "Your thinking naturally finds the wide-angle lens. Details assemble into meaning, anecdotes into philosophy, and you teach almost without noticing you are doing it — people leave conversations with you carrying frameworks they will quietly use for years. **Making sense of things is your native art**, and generosity with it comes easily to you.\n\nThe discipline is precision. Big ideas earn their keep only when the small facts underneath them hold, and one wrong number can discredit a whole true vision. Practice **checking the details your enthusiasm skipped** before you publish the panorama. Then keep teaching — the world has plenty of pedants and nowhere near enough people who can see whole." },
  "mercury-jupiter-sextile": { title: "Mercury sextile Jupiter", body: "Learning keeps extending its hand to you: the course that reroutes your thinking, the mentor met by accident, the conversation that quietly upgrades your entire model of the world. **Curiosity is your growth engine** — but engines idle until they are fed, and nobody else is responsible for the fuel.\n\nFeed it deliberately. Read past the required chapter, ask the bigger question in the meeting, follow the footnote that glitters at you. Your mind keeps outgrowing its rooms exactly as fast as you supply new material — no faster. **The education that changes your life is the one you assign yourself.** Keep assigning it, semester after self-invented semester." },
  "mercury-saturn-trine": { title: "Mercury trine Saturn", body: "Your mind builds to code. Thoughts arrive structured, promises arrive kept, and your word carries the specific weight of someone who thinks before speaking — colleagues route the important things through you because **what you say holds** under load. In a world addicted to hot takes, that is not dull. It is load-bearing.\n\nThe invitation is confidence in your own tempo. Slow conclusions are not late conclusions; yours simply cure longer and crack less. Practice **defending your thinking time** without apology — the considered answer tomorrow beats the clever one today, and the people worth working with know it. Depth is your dialect. Speak it proudly, at your own pace." },
  "mercury-saturn-sextile": { title: "Mercury sextile Saturn", body: "Mastery is genuinely available to you — offered through study, repetition, and the unglamorous middle chapters everyone else skims. Your mind rewards patience with authority: **what you learn slowly, you keep permanently**, and what you keep, you can stand on for the rest of a career.\n\nThe practice is choosing something worth ten years of attention, then actually giving it the years. One craft, one field, one language — depth over dabbling, always. Protect the daily hour; honor the boring repetitions; keep notes your future self will thank you for. **Expertise is compound interest for attention**, and this aspect guarantees the account pays out to anyone who keeps depositing." },
  "mercury-uranus-trine": { title: "Mercury trine Uranus", body: "Ideas reach you a beat before they reach everyone else. Your mind leaps laterally, connects the unconnected, and finds the exit nobody else saw — all without the static that usually rides along with this kind of brilliance. In lived life: **you are the one who reframes the stuck problem** in a single sentence, then wonders why everyone looks stunned.\n\nThe practice is capture. Insight this quick evaporates unless it is caught — keep the notebook, the voice memos, the folder of half-ideas, because **the flash you do not record never happened.** And share the strange thoughts sooner than feels safe: what sounds obvious to you is often five years early to everyone else in the room." },
  "mercury-uranus-sextile": { title: "Mercury sextile Uranus", body: "Breakthrough thinking is on offer whenever you break routine. New inputs — strange books, unlikely conversations, a different route home — reliably spark connections in you that pure effort at the desk cannot force. **Novelty is your mind's fuel**, delivered on request, invoiced only in willingness.\n\nSo treat novelty as a discipline rather than a distraction. One book per month from a shelf you never visit; one real conversation with someone whose life diverges completely from yours; one assumption deliberately turned upside down and shaken. **Your best ideas live just outside your habits** — and this aspect hands you the map every single time you are willing to wander." },
  "mercury-neptune-trine": { title: "Mercury trine Neptune", body: "Language and imagination share a bloodstream in you. Metaphor comes easily, intuition arrives dressed as a hunch that is usually right, and you can say the unsayable thing so gently that people can finally bear to hear it. **You translate between the literal and the felt** — a rare bilingualism the world quietly depends on more than it admits.\n\nPair the poetry with verification. A mind this fluid deserves banks as well as current: check the fact, source the claim, ask whether the beautiful explanation is also the accurate one. **Rigor does not cost you the magic** — it is what lets other people trust the magic enough to follow it somewhere real." },
  "mercury-neptune-sextile": { title: "Mercury sextile Neptune", body: "Your rational mind keeps receiving postcards from somewhere softer — images, symbols, sudden knowings that arrive without their paperwork. The offer here is **a working partnership between logic and dream**: analysis that does not strangle intuition, intuition that does not dodge analysis, each one covering the other's blind spot.\n\nHonor both sides of the correspondence. Write the dream down, then interrogate it over breakfast; trust the hunch, then test it against the facts. **The hunch you can articulate clearly outperforms instinct or analysis alone** — and that articulation is your practice. Ten minutes with a journal most mornings keeps the channel clean and the postcards coming." },
  "mercury-pluto-trine": { title: "Mercury trine Pluto", body: "You think like a diver, not a skimmer. Surfaces bore you; motives, subtexts, and root causes are where your mind naturally settles, and your insight can be surgical — you see the machinery behind what people say, sometimes before they do. **Depth of understanding is your instrument**, and it very rarely misses.\n\nWield it kindly. Seeing through people is a power best used to understand them, not to win against them — the same x-ray that finds the wound can either name it gently or press on it. Practice **investigation in service of intimacy**: ask the deeper question because you care about the answer, and let people surprise your analysis sometimes. They will." },
  "mercury-pluto-sextile": { title: "Mercury sextile Pluto", body: "The deeper question is always available to you — the one underneath the polite one. Research, honest inquiry, the conversation that goes one layer further than comfort suggested: these sharpen your mind into an instrument of real consequence. **You are offered the truth beneath the transcript**, whenever you are willing to actually ask for it.\n\nThe practice is gentle persistence. Ask what others will not — kindly, once more than feels natural — and extend the same inquiry inward: what am I not telling myself this season? **Every honest answer compounds your clarity.** Investigation, for you, is not suspicion of the world. It is devotion to the real, and the real rewards it." },
  "venus-mars-trine": { title: "Venus trine Mars", body: "Desire and affection cooperate in you instead of quarreling. You can pursue what you love with warmth and love what you pursue without losing yourself — an easy magnetism that needs no strategy behind it. In lived life: **wanting and being wanted do not contradict in you**, and connection tends to find its rhythm unusually fast.\n\nThe refinement: passion this smooth can go unexamined. Winning affection comes so naturally that you can forget to check whether the prize is what you actually want, or just what was nearest. Practice the audit — **is this desire mine, or merely available?** Attraction is your fluent language; make sure it keeps saying things you mean." },
  "venus-mars-sextile": { title: "Venus sextile Mars", body: "Romance rewards your initiative. The first move, the planned surprise, the creative risk taken for love or for art — this aspect offers a green light to all of it. **Attraction responds to you rather than merely happening to you**, which is far better odds than most people are ever handed.\n\nSo make the move. Send the message, plan the date, start the collaboration, say the interest out loud before certainty arrives to authorize it — desire here is a muscle that grows with honest use. **The want you act on teaches you who you are**; the one you only rehearse in private teaches you nothing at all. Choose the better lesson." },
  "venus-jupiter-trine": { title: "Venus trine Jupiter", body: "Generosity is your native tongue. Pleasure, beauty, and goodwill multiply around you as if you carry a small climate of abundance — and mostly, you do: the table with room for one more, the celebration found inside an ordinary week. **Joy expands when you touch it**, and people reliably feel richer in your company than out of it.\n\nThe single caution written into this gift: more is not always richer. An appetite this blessed can skim across pleasures without fully tasting any of them. **Savoring is the skill that keeps sweetness sweet** — one thing wholly enjoyed over five things sampled. Practice slowness at the feast. The abundance turns out to be even bigger than you thought." },
  "venus-jupiter-sextile": { title: "Venus sextile Jupiter", body: "Delight keeps making you offers: the trip, the gathering, the collaboration that turns into friendship, the acquaintance who quietly becomes family. Social luck runs through this aspect — **activated entirely by your willingness to show up**, and dormant the moment you stop.\n\nSo show up, and better yet, host. Extend the invitation you have been waiting to receive; set the table; be the reason two good people met. Abundance here works like a tide you can start yourself — **generosity circulates back to its source**, reliably, at this address. The only way to lose this aspect's gifts is to keep waiting for someone else to go first." },
  "venus-saturn-trine": { title: "Venus trine Saturn", body: "You love like a long-term investor. Loyalty comes naturally, your taste runs toward the enduring over the trendy, and your affections appreciate with time — the friendship in its second decade, the love that improves with familiarity instead of eroding under it. **Your devotion has architecture**, and the people you choose get to live inside it.\n\nThe practice is letting spontaneity in through the good windows you built. Even the soundest houses need air: the unplanned trip, the ridiculous gift, tenderness expressed off-schedule and out of character. **Permanence and play are not rivals.** You have already proven you can stay. Let yourself also delight, on purpose, in what you are staying for." },
  "venus-saturn-sextile": { title: "Venus sextile Saturn", body: "Lasting love is offered to you as a practice, not a lottery. Showing up on the ordinary Tuesdays, keeping the small promises, choosing again after choosing once — **devotion built this way has real foundations**, the kind that inspections do not rattle and years do not erode.\n\nThe permission here matters, especially if the standard scripts never fit you: commitment is not a cage, it is a craft — and you get to design what yours looks like. Chosen family counts. Slow love counts. Arrangements without precedent count. **The vow you write yourself binds better than the one handed to you.** Keep the small promises; they are the whole cathedral." },
  "venus-uranus-trine": { title: "Venus trine Uranus", body: "You love with the windows open. Freedom and affection coexist in you without contradiction — you can adore someone and still need your own sky, and the right people find that magnetic rather than threatening. **Your love does not follow the template, and it was never supposed to** — that is design, not deficiency, and pretending otherwise costs you both.\n\nThe practice is letting closeness deepen past the point where it stops feeling novel. Newness is your comfort zone; the frontier, for you, is the familiar. Try staying present through the ordinary chapters — **intimacy's best material arrives after the novelty fades.** You can keep the whole sky and still land somewhere, on purpose, again and again." },
  "venus-uranus-sextile": { title: "Venus sextile Uranus", body: "Unconventional joy keeps offering itself: the unlikely friend, the sudden attraction that rearranges your assumptions, the aesthetic nobody else understands yet but will in five years. This aspect rewards you for **refusing the pre-approved script** in love and taste alike — the reward being relationships that actually fit the people in them.\n\nSo experiment openly. Build your bonds to their own specifications — the structure that serves the humans involved, not the diagram everyone inherited without asking. Let your taste run early; it usually is. **Your affections were never meant to come off a shelf**, and every honest experiment you run makes more room for the people still pretending." },
  "venus-neptune-trine": { title: "Venus trine Neptune", body: "You love the way tide loves shore — devotedly, and a little beyond reason. Beauty moves you to your foundations; romance, art, and compassion blur into one luminous instinct, and **you see the best possible version of everyone you love**, often long before they can see it themselves. That vision is half the reason they get there.\n\nKeep one eye clear. Adoring the real person is a higher art than adoring the dream of them, and your gift only matures when it can hold both at once. Practice noticing what is, right alongside what could be — **love the draft, not just the vision.** Devotion with its eyes open is the rarest beauty you will ever make." },
  "venus-neptune-sextile": { title: "Venus sextile Neptune", body: "Enchantment is available to you in small, steady servings: the song that dissolves a hard day, a kindness given anonymously, beauty noticed on an otherwise ordinary street. **The sublime keeps office hours for you** — brief ones, daily, easily missed by anyone moving too fast to look up.\n\nKeep the appointments. Accept the small offers regularly and your capacity for love stays soft without going blurry — and that balance is the entire gift. The practice: one act of unnecessary beauty per day, given or received, no exceptions for busy weeks. **Wonder is a habit before it is an event**, and yours is always one deliberate noticing away." },
  "venus-pluto-trine": { title: "Venus trine Pluto", body: "You were built for love that transforms rather than decorates. Depth of feeling comes naturally — intimacy that changes both people, loyalty rooted in bedrock, the kind of bond that survives precisely because of what it is honest about. **People are altered by loving you**, and the good ones are grateful for it long after.\n\nThe permission: intensity is not a requirement for worth. Some easy affections deserve room in a heart this deep — the light friendship, the uncomplicated pleasure, the love that asks nothing profound of either of you. **Not every bond must go to the underworld.** Let a few stay in the sun; they will teach you things the depths cannot." },
  "venus-pluto-sextile": { title: "Venus sextile Pluto", body: "Deeper connection keeps extending its invitation: the conversation past midnight, the honesty that risks the relationship and turns out to be the very thing that saves it. **Vulnerability, chosen on purpose, regenerates your bonds at the root** — this aspect guarantees the offer, never the automatic outcome. The choosing is yours.\n\nSo choose it, at a sustainable pace. One truer sentence per hard conversation; one guard lowered per season, with someone who has earned the sight of what is behind it. Passion, for you, is less a lightning strike than **a practice of going deeper on purpose** — and practiced steadily, it builds the kind of intimacy that strangers assume was luck." },
  "mars-jupiter-trine": {
    title: "Mars trine Jupiter",
    body: "Your effort scales. Where others push, you launch — action backed by faith that the leap will find its landing, and it usually does. Enthusiasm this natural can outpace planning, though. Aim the abundance; a rocket is only as good as its trajectory.",
  },
  "mars-jupiter-sextile": {
    title: "Mars sextile Jupiter",
    body: "Bold moves are on offer, and the odds tilt your way when you make them. This aspect pairs your drive with opportunity's timing — the pitch, the race, the venture that grows. Fortune here favors the one who starts. So start, slightly bigger than feels safe.",
  },
  "mars-saturn-trine": {
    title: "Mars trine Saturn",
    body: "Your drive comes with brakes, steering, and a full tank — controlled power, the rarest kind. You can sustain effort long after sprinters fade, building things that outlast enthusiasm. The invitation is to occasionally floor it. Discipline that never risks anything is just caution in armor.",
  },
  "mars-saturn-sextile": {
    title: "Mars sextile Saturn",
    body: "Endurance is offered to you as a trainable strength. Structure your ambition — the schedule, the milestone, the honest deadline — and your drive becomes something like architecture. This aspect won't hand you stamina unearned, but every disciplined season you complete adds permanent horsepower.",
  },
  "mars-uranus-trine": {
    title: "Mars trine Uranus",
    body: "You act on insight faster than most people finish forming it. Boldness and originality fuse in you without the crash-landings that usually attend this pairing — improvisation is your natural athletic event. Channel it toward something durable; brilliance in motion still needs a destination.",
  },
  "mars-uranus-sextile": {
    title: "Mars sextile Uranus",
    body: "The unconventional move is always available to you — the sideways solution, the rule bent at exactly the right moment. This aspect offers courage of the inventive kind. Practice small acts of productive rebellion and you'll have the reflex ready when the big moment demands it.",
  },
  "mars-neptune-trine": {
    title: "Mars trine Neptune",
    body: "Your drive flows toward the invisible: the vision, the cause, the art that doesn't exist yet. You act from inspiration rather than aggression, which gives your effort a strange gracefulness. The anchor you need is specificity. Dreams become deeds through deadlines, not just devotion.",
  },
  "mars-neptune-sextile": {
    title: "Mars sextile Neptune",
    body: "Inspired action is offered to you in a form most people never notice: the gentle persistence, the creative project pursued quietly, the compassion that actually gets up and does something. Answer that call regularly. Your strength was always meant to serve something it can't fully see.",
  },
  "mars-pluto-trine": {
    title: "Mars trine Pluto",
    body: "Your will has a bottomless reserve tank. When you commit, obstacles don't stop you so much as reroute you, and your persistence carries an almost geological patience. Power this steady must choose its purposes carefully — what you push at relentlessly, you eventually move.",
  },
  "mars-pluto-sextile": {
    title: "Mars sextile Pluto",
    body: "Deep drive is available on request: the training block, the turnaround, the habit rebuilt from the studs. This aspect offers regeneration through effort — every hard thing you finish returns strength with interest. Choose one worthy struggle at a time and become quietly unstoppable.",
  },
  "jupiter-saturn-trine": {
    title: "Jupiter trine Saturn",
    body: "Vision and structure shake hands in your chart. You dream in blueprints — big enough to matter, buildable enough to happen — and your judgment about what's worth the years is naturally sound. Trust it. This is the aspect of the life constructed on purpose.",
  },
  "jupiter-saturn-sextile": {
    title: "Jupiter sextile Saturn",
    body: "Sustainable growth keeps offering itself to you in sensible increments: the expansion that doesn't overextend, the risk with a foundation under it. When you pair your optimism with a plan, both get stronger. Steady, deliberate, compounding — that's your particular flavor of luck.",
  },
  "jupiter-uranus-trine": {
    title: "Jupiter trine Uranus",
    body: "Your luck arrives disguised as lightning — sudden openings, timely accidents, the right stranger at the right hour. You trust change enough to ride it, and the ride is usually upward. Stay generous with what the windfalls bring; freedom shared is freedom multiplied.",
  },
  "jupiter-uranus-sextile": {
    title: "Jupiter sextile Uranus",
    body: "Unexpected doors open near you more often than average — but only the ones you're standing close to. Curiosity is your positioning strategy. Explore widely, keep loose plans, and this aspect converts your openness into opportunities that look, from outside, like miracles of timing.",
  },
  "jupiter-neptune-trine": {
    title: "Jupiter trine Neptune",
    body: "Faith comes easily to you — not the doctrinal kind, but the felt sense that life is larger and kinder than it appears. Your compassion has range; your imagination has horizons. Ground it in one real practice, and the vastness becomes a home instead of a mist.",
  },
  "jupiter-neptune-sextile": {
    title: "Jupiter sextile Neptune",
    body: "Meaning keeps leaving small invitations at your door: the retreat, the cause, the art that reorganizes your priorities. Answer a few. This aspect offers a generous spiritual imagination that grows exactly as fast as you make room for it — no faster, and no slower.",
  },
  "jupiter-pluto-trine": {
    title: "Jupiter trine Pluto",
    body: "You grow by transforming, not by accumulating. Success has a way of finding you at depth — the ambitious project with soul, the influence earned through substance. Your convictions carry unusual gravity. Aim them at something bigger than winning, and your reach becomes genuinely regenerative.",
  },
  "jupiter-pluto-sextile": {
    title: "Jupiter sextile Pluto",
    body: "Profound growth is offered here in the form of worthy intensity: the mission that demands your whole self, the study that goes all the way down. Say yes to depth over breadth when the choice appears. Your expansions are meant to have roots as long as their branches.",
  },
  "saturn-uranus-trine": {
    title: "Saturn trine Uranus",
    body: "You innovate without burning the workshop down. Old structures and new ideas cooperate in you — you can honor a tradition while quietly rebuilding it from inside, and institutions tend to trust you with their futures. That's a rare commission. Use it before someone less careful does.",
  },
  "saturn-uranus-sextile": {
    title: "Saturn sextile Uranus",
    body: "Practical revolution is your standing offer: modernize the process, update the rule, renovate rather than demolish. When you deliberately pair patience with experiment, change sticks instead of snapping back. You're built to be the bridge generation — the one that makes the new thing last.",
  },
  "saturn-neptune-trine": {
    title: "Saturn trine Neptune",
    body: "You can build a house for a dream without crushing it. Discipline and imagination cooperate in you naturally — the meditation practice kept for decades, the art with craftsmanship, the ideal made policy. Most visionaries lack your patience; most builders lack your vision. Work the overlap.",
  },
  "saturn-neptune-sextile": {
    title: "Saturn sextile Neptune",
    body: "This aspect offers you the quiet art of making the intangible real: the routine that protects your creativity, the boundary that preserves your compassion. Take the offer in small, regular commitments. Dreams with schedules come true at a rate that surprises everyone but you.",
  },
  "saturn-pluto-trine": {
    title: "Saturn trine Pluto",
    body: "Your endurance regenerates. Where pressure erodes others, it consolidates you — hardship becomes structure, structure becomes strength, and your authority accrues like sediment turning to stone. Just verify, now and then, that what you're so capably enduring is still worth the strength it costs.",
  },
  "saturn-pluto-sextile": {
    title: "Saturn sextile Pluto",
    body: "Deep, deliberate rebuilding is always available to you: the finances restructured, the boundary finally enforced, the foundation replaced one beam at a time. This aspect offers transformation at a sustainable pace. Take it seriously and slowly — what you rebuild this way does not fall twice.",
  },
  "uranus-neptune-trine": {
    title: "Uranus trine Neptune",
    body: "Innovation and imagination share a generational current in you, and you sit comfortably in it. Your idealism is inventive; your inventions have soul. Where you make this personal is in application — lending your era's visionary streak to one project with your name on it.",
  },
  "uranus-neptune-sextile": {
    title: "Uranus sextile Neptune",
    body: "Your generation was offered a rare collaboration between the futurist and the mystic, and it runs quietly through you. Activate it personally: pair a new tool with an old longing, technology with tenderness. The world-changing happens at that seam, one deliberate experiment at a time.",
  },
  "uranus-pluto-trine": {
    title: "Uranus trine Pluto",
    body: "Deep change moves through your generation like a current under ice, and you swim in it with unusual ease. Upheaval doesn't just happen to you; it works for you. The personal assignment: pick one broken system you actually touch, and be the reason it evolves.",
  },
  "uranus-pluto-sextile": {
    title: "Uranus sextile Pluto",
    body: "Your cohort carries an open invitation to reinvent power itself — how it's held, shared, and questioned. In your own life, that looks like small structural rebellions: renegotiating a role, dismantling an inherited assumption. Each one you complete makes the collective shift a little more real.",
  },
  "neptune-pluto-trine": {
    title: "Neptune trine Pluto",
    body: "The dreamer and the depths are on good terms across your whole generation, and through you personally. Spiritual imagination and transformative instinct reinforce each other quietly, over decades. Your part is small and specific: let what genuinely moves you also genuinely change you.",
  },
  "neptune-pluto-sextile": {
    title: "Neptune sextile Pluto",
    body: "A slow, background offer runs through your era: the chance to let vision and depth renew each other across a lifetime. You claim your share in ordinary ways — the practice kept, the meaning made from loss, the quiet refusal to become cynical. That refusal is the work.",
  },
};
